// Initialise the ping attempt counter for retry logic
return [{
  json: {
    targetUrl: 'https://demo.realworld.io',
    attempt: 1,
    maxAttempts: 3,
    pingStart: Date.now()
  }
}];

// Record response time and status
const pingStart = $('Initialise Ping State').first().json.pingStart;
const attempt   = $('Initialise Ping State').first().json.attempt;
const resp      = $input.first().json;

const responseTimeMs = Date.now() - pingStart;
const statusCode     = resp.statusCode ?? resp.status ?? 0;
const ok             = statusCode === 200;
const slow           = responseTimeMs > 3000;   // >3 s counts as degraded

return [{
  json: {
    targetUrl:      'https://demo.realworld.io',
    statusCode,
    ok,
    slow,
    responseTimeMs,
    attempt,
    checkedAt:      new Date().toUTCString(),
    shouldAlert:    !ok || slow
  }
}];

// Increment attempt counter and reset ping start time
const prev = $input.first().json;
return [{
  json: {
    targetUrl:   prev.targetUrl,
    attempt:     (prev.attempt || 1) + 1,
    maxAttempts: 3,
    pingStart:   Date.now()
  }
}];

// Build a Discord alert message for downtime or slow response
const r = $input.first().json;

let severity = '';
let detail   = '';

if (!r.ok) {
  severity = r.statusCode === 0
    ? '🔴 **DOWN** (connection failed / timeout)'
    : `🔴 **ERROR** (HTTP ${r.statusCode})`;
  detail = `The app returned a non-200 status after ${r.attempt} attempt(s).`;
} else if (r.slow) {
  severity = '🟡 **SLOW** (response degraded)';
  detail   = `Response time: **${r.responseTimeMs} ms** (threshold: 3 000 ms).`;
}

const msg = [
  `## Uptime Alert – demo.realworld.io`,
  `**Status:** ${severity}`,
  `**Response Time:** ${r.responseTimeMs} ms`,
  `**HTTP Status:** ${r.statusCode || 'N/A (connection error)'}`,
  `**Attempts:** ${r.attempt} / 3`,
  `**Detail:** ${detail}`,
  `**Checked at:** ${r.checkedAt}`,
  `**Target:** ${r.targetUrl}`
].join('\n');

return [{ json: { content: msg } }];

// Store result in static data for daily summary
// n8n's staticData persists across executions of the same workflow
const data   = $input.first().json;
const stored = $getWorkflowStaticData('global');

if (!stored.checks) stored.checks = [];

stored.checks.push({
  ts:            Date.now(),
  statusCode:    data.statusCode,
  ok:            data.ok,
  responseTimeMs: data.responseTimeMs
});

// Keep only the last 288 checks (24 h × 12 checks/h at 5-min interval)
if (stored.checks.length > 288) {
  stored.checks = stored.checks.slice(-288);
}

const total  = stored.checks.length;
const passed = stored.checks.filter(c => c.ok).length;
const uptime = ((passed / total) * 100).toFixed(2);
const avgMs  = Math.round(
  stored.checks.reduce((s, c) => s + (c.responseTimeMs || 0), 0) / total
);

stored.dailySummary = { total, passed, uptime, avgMs };

return [{ json: { logged: true, uptime, avgMs, total } }];

// Read stored stats and build a daily summary
const stored = $getWorkflowStaticData('global');
const s      = stored.dailySummary || { total: 0, uptime: 'N/A', avgMs: 'N/A' };

const checks  = stored.checks || [];
const last24h = checks.filter(c => c.ts > Date.now() - 86400000);
const failed  = last24h.filter(c => !c.ok).length;

const msg = [
  '## 📊 Daily Uptime Summary – demo.realworld.io',
  `**Date:** ${new Date().toUTCString()}`,
  `**Checks in last 24h:** ${last24h.length}`,
  `**Uptime:** ${s.uptime}%`,
  `**Failed checks:** ${failed}`,
  `**Avg response time:** ${s.avgMs} ms`,
  `**Status:** ${parseFloat(s.uptime) >= 99 ? '✅ Healthy' : parseFloat(s.uptime) >= 95 ? '🟡 Degraded' : '🔴 Incident'}`
].join('\n');

return [{ json: { content: msg } }];

const err = $input.first().json;
return [{
  json: {
    content: [
      '🚨 **Uptime Monitor Workflow Error**',
      `**Node:** ${err.execution?.lastNodeExecuted ?? 'Unknown'}`,
      `**Error:** ${err.execution?.error?.message ?? JSON.stringify(err)}`,
      `**Time:** ${new Date().toUTCString()}`
    ].join('\n')
  }
}];
